	<style>

	/*** Mobile Menu ***/

	.hamb{
        cursor: pointer;
        float: right;
        padding: 40px 20px;
    }

    .hamb-line {
        background: #fff;
        display: block;
        height: 2px;
        position: relative;
        width: 24px;

    }

    .hamb-line::before,
    .hamb-line::after{
        background: #fff;
        content: '';
        display: block;
        height: 100%;
        position: absolute;
        transition: all .2s ease-out;
        width: 100%;
    }
    .hamb-line::before{
        top: 10px;
    }
    .hamb-line::after{
        top: -10px;
    }

    .side-menu {
        display: none;
    }

    .side-menu:checked ~ nav{
        max-height: 100%;
    }
    .side-menu:checked ~ .hamb .hamb-line {
        background: transparent;
    }
    .side-menu:checked ~ .hamb .hamb-line::before {
        transform: rotate(-45deg);
        top:0;
    }
    .side-menu:checked ~ .hamb .hamb-line::after {
        transform: rotate(45deg);
        top:0;
    }

    nav#main-nav {
        /* position: relative; */
    }

    @media screen and (min-width: 20rem) {

        input#side-menu {
            width: 100%;
            height: 100%;
            position: absolute;
            z-index: 999999;
        }

        .side-menu ~ div#primary-menu {
            transition: max-height .5s;
        }

        .side-menu:not(:checked) ~ div#primary-menu {
            top: 100%;
            position: absolute;
            right: -999999px;
            max-height: 0px;
            opacity: 1;
            visibility: visible;
        }

        .side-menu:checked ~ div#primary-menu {
            top: 100%;
            position: absolute;
            right: 0;
            max-height: 1000px;
            opacity: 1;
            visibility: visible;
            width: 100%;
            padding: 25px!important;
            margin-top: 0!important;
            overflow: scroll;
            height: 100vh;
        }

        .side-menu:checked ~ div#primary-menu li {
            color: #fff;
            padding: 5px 0 10px;
        }
    }

    @media screen and (min-width: 80rem) {
        .hamb{
            display: none;
        }

        .side-menu ~ div#primary-menu {
            transition: none;
        }

        .side-menu:checked ~ div#primary-menu {
            position: static;
            /* overflow: visible; */
        }

        .side-menu:not(:checked) ~ div#primary-menu {
            top: 100%;
            position: static;
            right: -999999px;
            max-height: 1000px;
            opacity: 1;
            visibility: visible;
        }

        .side-menu:checked ~ div#primary-menu li {
            color: #000;
        }
    }
	</style>
